import xml.etree.ElementTree as ET

def parse_xml(file):
    tree = ET.parse(file)
    root = tree.getroot()
    
    result_dict = {}
    
    for child in root:
        name = child.tag
        value = child.text
        
        if value is not None:
            value = value.strip()
            
        result_dict[name] = value
    
    return result_dict